/* SQL ID : AsmntProIndiDAO.selectTarget 설 명 : 과제 대상자 조회 */ SELECT Z.* FROM ( SELECT ATNDLC.ATNDLC_ID , ATNDLC.USER_ID , USR.USERNM , (SELECT DEPTNM FROM TB_LMS_DEPT WHERE DEPT_ID = USR.DEPT_ID) AS DEPTNM FROM TB_LMS_ATNDLC ATNDLC JOIN TB_LMS_USER USR ON ATNDLC.USER_ID = USR.USER_ID
JOIN TB_LMS_ASMT_SBMSN SBMSN ON SBMSN.USER_ID = ATNDLC.USER_ID AND SBMSN.ASMT_ID = #{asmtId} AND SBMSN.DELYN = 'N' -- AND SBMSN_STSCD = 'NON_SBMSN' AND SBMSN.RESBMSNYN = 'N'
WHERE ATNDLC.SBJCT_ID = #{sbjctId} AND ATNDLC.ATNDLC_STSCD = 'ATNDLC' AND USR.USER_STSCD = 'ACTV' AND ATNDLC.AUDITYN = 'N' ) Z ORDER BY Z.USERNM

mapper.insert:
		/*
             SQL ID : AsmntProIndiDAO.insertTarget
             	설  명 : 과제 대상자 등록
         */
		INSERT INTO TB_LMS_ASMT_TRGT (
			ASMT_SBMSN_TRGT_ID
			, ASMT_ID
			, USER_ID
			, REG_DTTM
			, RGTR_ID
		) VALUES
		(
			#{asmtSbmsnTrgtId}
			, #{asmtId}
			, #{userId}
			, FN_DTTM()
			, #{rgtrId}
		)

		/*
             SQL ID : AsmntProIndiDAO.insertTargetList
             	설  명 : 과제 대상자 목록 등록
         */
		INSERT INTO TB_LMS_ASMT_TRGT (
			ASMT_SBMSN_TRGT_ID
		  , ASMT_ID
		  , USER_ID
		  , REG_DTTM
		  , RGTR_ID
		)

		SELECT
			#{item.asmtSbmsnTrgtId}
		  , #{item.asmtId}
		  , #{item.userId}
		  , FN_DTTM()
		  , #{item.rgtrId}
		FROM DUAL

		/*
             SQL ID : AsmntProIndiDAO.insertTargetFile
             	설  명 : 과제 대상자 파일 등록
         */
		INSERT INTO TB_LMS_ASMNT_SBMT_FILE (
			  ASMT_ID
			, ASMT_SBMSN_ID
			, FILE_ID
			, RGTR_ID
			, FRST_INQ_DTTM
		) VALUES (
			  #{asmtId}
			, #{asmtSbmsnId}
			, 0
			, #{userId}
			, FN_DTTM()
		)

		/*
             SQL ID : AsmntProIndiDAO.insertTargetFileList
             	설  명 : 과제 대상자 파일 목록 등록
         */
         INSERT ALL

         INTO TB_LMS_ASMNT_SBMT_FILE (
			  ASMT_ID
			, ASMT_SBMSN_ID
			, FILE_ID
			, RGTR_ID
			, FRST_INQ_DTTM
		) VALUES (
			  #{item.asmtId}
			, #{item.asmtSbmsnId}
			, 0
			, #{item.userId}
			, FN_DTTM()
		)

    SELECT * FROM DUAL

mapper.delete:
		/*
             SQL ID : AsmntProIndiDAO.deleteTarget
             	설  명 : 과제 대상자 삭제
         */
		DELETE FROM TB_LMS_ASMT_SBMSN
		 WHERE ASMT_ID = #{asmtId}

		/*
             SQL ID : AsmntProIndiDAO.deleteTargetFile
             	설  명 : 과제 대상자 파일 삭제
         */
		DELETE FROM TB_LMS_ASMNT_SBMT_FILE
		 WHERE ASMT_ID = #{asmtId}

mapper.update:
		/*
             SQL ID : AsmntProIndiDAO.updateScore
             	설  명 : 과제 대상자 성적 수정
         */
		UPDATE TB_LMS_ASMT_SBMSN
		   SET MDFR_ID = #{userId}
			   , MOD_DTTM = FN_DTTM()
			   , SCR =


			   			( SELECT S1.SCR FROM ( SELECT CASE WHEN SCR + #{SCR} < 0 THEN 0
  								   						     WHEN SCR + #{SCR} > 100 THEN 100
					                       				     ELSE SCR + #{SCR}
					                                     END SCR
								   			   	   FROM TB_LMS_ASMT_SBMSN
								   			   	  WHERE ASMT_ID = #{asmtId}
						       					 	AND STD_ID = #{stdNo} ) S1 )


			   			#{SCR}


			   , EVLYN = 'Y'
		 WHERE ASMT_ID = #{asmtId}
	       AND STD_ID = #{stdNo}

		/*
             SQL ID : AsmntProIndiDAO.updateScoreBatch
             	설  명 : 과제 대상자 성적 일괄 수정
         */

		UPDATE TB_LMS_ASMT_SBMSN
		   SET MDFR_ID = #{item.mdfrId}
			   , MOD_DTTM = FN_DTTM()
			   , SCR = #{item.SCR}
			   , EVLYN = 'Y'
		 WHERE ASMT_ID = #{item.asmtId}
	       AND STD_ID = #{item.stdNo}

		/*
             SQL ID : AsmntProIndiDAO.updateMemo
             	설  명 : 과제 대상자 메모 수정
         */
		UPDATE TB_LMS_ASMT_SBMSN
		   SET MDFR_ID = #{userId}
			   , MOD_DTTM = FN_DTTM()
			   , SCR_MEMO = #{scrMemo}
		 WHERE ASMT_ID = #{asmtId}
	       AND STD_ID = #{stdNo}

		/*
             SQL ID : AsmntProIndiDAO.updateBest
             	설  명 : 과제 대상자 우수과제 선정
         */
		UPDATE TB_LMS_ASMT_SBMSN
		   SET MDFR_ID = #{userId}
			   , MOD_DTTM = FN_DTTM()
			   , EXLN_ASMTYN = #{exlnAsmtyn}
		 WHERE ASMT_ID = #{asmtId}
	       AND STD_ID = #{stdNo}

		/*
             SQL ID : AsmntProIndiDAO.deleteResend
             	설  명 : 제재출 대상자 제거
         */
		UPDATE TB_LMS_ASMT_SBMSN
		   SET MDFR_ID = #{userId}
			   , MOD_DTTM = FN_DTTM()
			   , RESEND_YN = 'N'
			   , SBMSN_STSCD = IF(SBMSN_STSCD = 'RE', 'NO', SBMSN_STSCD)
		 WHERE ASMT_ID = #{asmtId}
		 AND RESEND_YN = 'Y'


                 AND STD_ID NOT IN

                     #{item}

		/*
             SQL ID : AsmntProIndiDAO.updateResend
             	설  명 : 제재출 대상자 수정
         */
		UPDATE TB_LMS_ASMT_SBMSN
		   SET MDFR_ID = #{userId}
			   , MOD_DTTM = FN_DTTM()
			   , RESEND_YN = 'Y'
			   , SCR = NULL
		 WHERE ASMT_ID = #{asmtId}
	       AND STD_ID = #{stdNo}
	       AND RESEND_YN = 'N'
	       AND SBMSN_STSCD = 'NO'

mapper.delete:
		/*
             SQL ID : AsmntProIndiDAO.deleteTargetByStdNo
             	설  명 : 과제 대상자 단일 삭제
