         */
		DELETE FROM TB_LMS_ASMNT_JOIN_HSTY
		 WHERE ASMT_ID = #{asmtId}
		   AND STD_ID = #{stdNo}

		/*
             SQL ID : AsmntProIndiDAO.deleteTargetFdbkByStdNo
             	설  명 : 과제 대상자 피드백 단일 삭제
         */
		DELETE FROM TB_LMS_ASMNT_FDBK
		 WHERE ASMT_ID = #{asmtId}
		   AND STD_ID = #{stdNo}

mapper.update:
		/*
             SQL ID : AsmntProIndiDAO.canecelTargetMutScore
             	설  명 : 과제 대상자 점수 부여 취소
         */
         UPDATE TB_LMS_ASMT_SBMSN
         	SET MDFR_ID = #{userId}
			  , MOD_DTTM = FN_DTTM()
			  , SCR = NULL
			  , EVLYN = 'N'
		  WHERE ASMT_ID = #{asmtId}
		    AND STD_ID = #{stdNo}
